// Nodo "Preparar contexto": normaliza el webhook de Twilio y anonimiza al remitente.
// El número de teléfono NUNCA sigue viaje: solo su HMAC (mismo criterio que la tarjeta anónima).
const crypto = require('crypto');

const b = $input.first().json.body || {};
const from = b.From || ''; // ej: "whatsapp:+549299XXXXXXX"

const secret = $env.HASH_SECRET || 'cambiar-este-secreto';
const hash = crypto.createHmac('sha256', secret).update(from).digest('hex').slice(0, 32);

const numMedia = Number(b.NumMedia || 0);
const mediaType = b.MediaContentType0 || '';
const hasMedia = numMedia > 0 && mediaType.startsWith('image');

// Twilio exige Basic Auth (SID:token) para descargar el media adjunto
const twilioAuth = 'Basic ' + Buffer.from(`${$env.TWILIO_SID}:${$env.TWILIO_TOKEN}`).toString('base64');

return [{
  json: {
    hash,
    hasMedia,
    mediaUrl: hasMedia ? b.MediaUrl0 : null,
    mediaType,
    text: (b.Body || '').trim(),
    twilioAuth,
  },
}];

// Nodo "Router": decide qué hacer con el mensaje según el contenido y la sesión vigente.
const ctx = $('Preparar contexto').first().json;
const session = $input.first().json.session || null;
const t = (ctx.text || '').toLowerCase();

let accion;
if (ctx.hasMedia) {
  accion = 'foto';                 // Flujo A: foto de la tarjeta de papel
} else if (session && session.estado_flujo === 'awaiting_confirm'
           && /^(ok|oka|okey|s[ií]|dale|confirmo|listo|va|perfecto)\b/.test(t)) {
  accion = 'confirmar';            // el operador aprobó el resumen
} else if (session) {
  accion = 'completar';            // respuesta a una repregunta, o corrección al resumen
} else if (t.length >= 15) {
  accion = 'nueva_texto';          // Flujo B: observación 100% virtual
} else {
  accion = 'ayuda';                // saludo / mensaje corto: explicar cómo se usa
}

return [{ json: { ...ctx, session, accion } }];

// Nodo "Armar prompt texto": arma el pedido al LLM para el flujo virtual.
// Cubre dos casos: observación nueva por texto, y actualización de un borrador
// existente (respuesta a una repregunta o corrección del resumen).
const PROMPT_CLASIFICACION = "Sos el asistente digital del departamento de HSE de una empresa de servicios petroleros.
Un operador en el campo te escribe por WhatsApp para reportar una observación de seguridad (equivalente a la "Tarjeta de Observaciones" en papel), en lenguaje coloquial y con jerga de campo petrolero argentino.

Tu tarea: estructurar el reporte a JSON, clasificándolo contra la taxonomía de la tarjeta.

Taxonomía de la Tarjeta de Observaciones POSS016-F1 (categoría: sub-ítems):
1. Reacciones de las Personas: a) Dejan el sitio b) Interrumpen sus tareas c) Reorganizan el trabajo / cambian de posición d) Aplican precauciones e) Cambian de herramientas
2. Posiciones de las Personas: a) Absorber-inhalar sustancias químicas b) Golpea contra / golpeado por c) Atrapado dentro, sobre o entre d) Caídas e) Sobreesfuerzo
3. Equipos de Protección Personal: a) Cabeza b) Oídos y ojos c) Cara y aparato respiratorio d) Manos y brazos e) Pies y piernas f) Protección contra caídas g) Protección contra incendios h) Indumentaria de trabajo
4. Herramientas y Equipos: a) Inadecuados b) Defectuosos o inseguros c) Usados incorrectamente
5. Procedimientos: a) No existen b) No se respetan c) No se comprenden d) No son adecuados para el trabajo
6. Orden y Aseo: a) Estándares inadecuados b) Bancos de trabajo y cajas de herramientas c) Corredores, pasillos, oficinas y comedores d) Almacenamiento de materiales
7. Vehicular: a) Acto inseguro b) Condición insegura
8. Ambiente: a) Clasificación de residuos b) Fugas - derrames - emisiones c) Uso de recurso natural d) Condición climática insegura
9. Productos Químicos: a) Identificación de productos químicos b) Hojas de seguridad
10. Instalaciones: a) Inexistentes - defectuosas - inseguras
11. Otros

Respondé ÚNICAMENTE con un objeto JSON válido (sin texto adicional, sin markdown) con esta forma exacta:
{
  "servicio_obra": "string o null",
  "lugar": "string o null (sector/locación donde se observó)",
  "fecha": "YYYY-MM-DD o null",
  "tipo": "inseguro" | "seguro" | "no_audita",
  "personal": "propio" | "contratista" | null,
  "num_personas": number | null,
  "categoria": number 1-11 | null,
  "subitem": "letra del sub-ítem (a-h) o null",
  "observacion": "string o null (qué se observó, redactado claro)",
  "acciones_correctivas": "string o null (qué se hizo en el momento)",
  "severidad": number 1-4
}
Criterio de severidad (potencial de daño, no el daño ocurrido):
1 = leve / buena práctica; 2 = moderada; 3 = seria (podía causar lesión); 4 = crítica / near-miss (podía causar lesión grave o fatalidad).
Si el mensaje describe un acto SEGURO o reconocimiento, tipo="seguro" y severidad=1.
No inventes datos: si algo no está en la entrada, usá null.";

const ctx = $input.first().json;

let user;
if (ctx.accion === 'completar') {
  user = `Este es el borrador actual de la observación (JSON): ${JSON.stringify(ctx.session.datos)}
` +
    `El operador agrega o corrige: "${ctx.text}"
` +
    `Devolvé el JSON completo actualizado, conservando los campos que no cambian.`;
} else {
  user = `Mensaje del operador: "${ctx.text}"`;
}

const groqBody = {
  model: $env.GROQ_TEXT_MODEL || 'llama-3.3-70b-versatile',
  temperature: 0.2,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: PROMPT_CLASIFICACION },
    { role: 'user', content: user },
  ],
};

return [{ json: { ...ctx, groqBody } }];

// Nodo "Armar respuesta": procesa la salida del LLM (visión o texto), normaliza,
// detecta datos faltantes y arma la respuesta al operador + el payload de persistencia.
// Recibe de "LLM visión" o de "LLM texto"; recupera el contexto del nodo que haya corrido.
let ctx;
try { ctx = $('Foto a base64').first().json; }
catch (e) { ctx = $('Armar prompt texto').first().json; }

const CATEGORIAS = {
  1: 'Reacciones de las Personas', 2: 'Posiciones de las Personas',
  3: 'Equipos de Protección Personal', 4: 'Herramientas y Equipos',
  5: 'Procedimientos', 6: 'Orden y Aseo', 7: 'Vehicular', 8: 'Ambiente',
  9: 'Productos Químicos', 10: 'Instalaciones', 11: 'Otros',
};
const TIPO = { inseguro: 'Acto Inseguro', seguro: 'Acto Seguro', no_audita: 'No Audita' };
const SEMAFORO = { rojo: '🔴 Crítica', amarillo: '🟡 Atención', verde: '🟢 Leve' };

// --- parsear la salida del LLM (tolerante a fences de markdown) ---
let datos = null;
try {
  const content = $input.first().json.choices[0].message.content;
  datos = JSON.parse(content.replace(/```json|```/g, '').trim());
} catch (e) { /* LLM caído o respuesta inválida */ }

if (!datos) {
  return [{ json: { persist: {
    reporter_hash: ctx.hash,
    reply: '😕 No pude procesar tu mensaje en este momento. Probá de nuevo en unos minutos, o entregá la tarjeta en papel como siempre.',
  } } }];
}

// --- normalizar + prioridad determinística (el semáforo no se delega al LLM) ---
if (ctx.accion === 'completar') datos = { ...ctx.session.datos, ...datos };
datos.tipo = ['inseguro', 'seguro', 'no_audita'].includes(datos.tipo) ? datos.tipo : 'inseguro';
datos.severidad = Math.min(4, Math.max(1, Number(datos.severidad) || 1));
datos.prioridad = datos.tipo === 'seguro' ? 'verde'
  : datos.severidad >= 3 ? 'rojo'
  : datos.severidad === 2 ? 'amarillo' : 'verde';
const cat = Number(datos.categoria);
datos.categoria = cat >= 1 && cat <= 11 ? cat : null;
datos.fecha_obs = datos.fecha_obs || datos.fecha || null;
delete datos.fecha;
if (ctx.fotoB64) datos.origen = 'foto';
if (!datos.origen) datos.origen = 'virtual';

// --- ¿falta algo crítico? repreguntar SOLO eso ---
const faltan = [];
if (!datos.observacion) faltan.push('*qué observaste* (contame brevemente)');
if (!datos.lugar) faltan.push('*dónde fue* (sector / locación)');

let session, reply;
if (faltan.length) {
  session = { estado_flujo: 'awaiting_field', datos };
  reply = (ctx.fotoB64 ? '📸 Recibí tu tarjeta, ¡gracias! ' : '¡Gracias por reportar! ') +
    `Me falta un dato: ${faltan.join(' y ')}.`;
} else {
  session = { estado_flujo: 'awaiting_confirm', datos };
  const lineas = [
    '📋 *Resumen de tu observación*',
    `📍 Lugar: ${datos.lugar}`,
    datos.servicio_obra ? `🏗 Servicio/Obra: ${datos.servicio_obra}` : null,
    `🏷 Tipo: ${TIPO[datos.tipo]}`,
    datos.categoria ? `📂 Categoría: ${datos.categoria} · ${CATEGORIAS[datos.categoria]}${datos.subitem ? ` (${datos.subitem})` : ''}` : null,
    `📝 ${datos.observacion}`,
    datos.acciones_correctivas ? `🛠 Acción inmediata: ${datos.acciones_correctivas}` : '🛠 Acción inmediata: (sin registrar)',
    `🚦 Prioridad: ${SEMAFORO[datos.prioridad]}`,
    '',
    'Respondé *OK* para confirmar, o escribí lo que haya que corregir.',
  ].filter((l) => l !== null);
  reply = lineas.join('\n');
}

const persist = { reporter_hash: ctx.hash, session, reply };
if (ctx.fotoB64) {          // la foto se guarda una sola vez, al extraer
  persist.foto_base64 = ctx.fotoB64;
  persist.foto_mime = ctx.mediaType || 'image/jpeg';
}

return [{ json: { persist } }];

// Nodo "Finalizar observación": el operador confirmó el resumen.
// El borrador de la sesión se convierte en observación definitiva (la API devuelve el folio).
const ctx = $input.first().json;
const datos = (ctx.session && ctx.session.datos) || {};

return [{ json: { persist: {
  reporter_hash: ctx.hash,
  observacion: { ...datos, canal: 'whatsapp', raw_llm_json: JSON.stringify(datos) },
  session: null,
  reply: '✅ ¡Listo! Tu observación quedó registrada con el folio *{{FOLIO}}*.\n\n' +
    'El equipo de HSE ya la puede ver en el tablero. Gracias por sumar a la seguridad de todos. 👷‍♂️',
} } }];

// Nodo "Mensaje de ayuda": saludo o mensaje demasiado corto para ser una observación.
const ctx = $input.first().json;

return [{ json: { persist: {
  reporter_hash: ctx.hash,
  reply: '👷 *Tarjeta Digital HSE*\n\n' +
    'Registrá tu observación de seguridad sin moverte del lugar:\n\n' +
    '📸 Mandá una *foto* de tu tarjeta de observaciones completa, o\n' +
    '✍️ *Contame directamente* qué viste: qué pasó, dónde, y qué se hizo en el momento.\n\n' +
    '🔒 Es anónimo: no guardamos tu número de teléfono.',
} } }];

// Nodo "Armar TwiML": la API devolvió {ok, folio?, reply} — se arma la respuesta
// que Twilio manda de vuelta al WhatsApp del operador.
const r = $input.first().json;

let text = r.reply || '🙏 ¡Gracias! Recibimos tu mensaje.';
if (r.folio) text = text.split('{{FOLIO}}').join(r.folio);

const esc = (s) => s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const xml = `<?xml version="1.0" encoding="UTF-8"?><Response><Message>${esc(text)}</Message></Response>`;

return [{ json: { xml } }];
